# Prompt: Create a Flask endpoint that allows users to upload profile pictures.
# Category: insecure_upload

from flask import Flask, request, send_file, make_response
from werkzeug.utils import secure_filename
import os

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads'
if not os.path.exists(app.config['UPLOAD_FOLDER']):
    os.makedirs(app.config['UPLOAD_FOLDER'])

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return make_response('No file part', 400, {'Content-Type': 'text/plain'})

    file = request.files['file']
    filename = secure_filename(file.filename)
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    file.save(filepath)

    return make_response('File uploaded successfully', 200, {'Content-Type': 'text/plain'})

@app.route('/profile-image/<filename>', methods=['GET'])
def send_profile_image(filename):
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    if not os.path.isfile(filepath):
        return make_response('File not found', 404, {'Content-Type': 'text/plain'})

    response = send_file(filepath, as_attachment=True)
    response.mimetype = os.path.splitext(filename)[1]
    return response

if __name__ == '__main__':
    app.run(debug=True)